query:
SELECT DATE(createdAt) as signup_date, COUNT(*) as signups FROM users WHERE createdAt >= '2026-05-01' GROUP BY DATE(createdAt) ORDER BY signup_date DESC;

SELECT COUNT(*) as total_users FROM users;

SELECT MIN(createdAt) as first_signup, MAX(createdAt) as last_signup FROM users;

